#!/bin/bash
# scripts/build_parse_expr_unit_test.sh — standalone parse_expr_pat_from_str unit test build
# Self-contained. Derives paths from $0.
# Requires: /tmp/test_parse_expr_pat.c (generated by the test session)
set -e
HERE="$(cd "$(dirname "$0")" && pwd)"
SRC="$HERE/src/frontend/snobol4"
ROOT="$HERE/src"
gcc -O0 -g -Wall -Wno-unused-function -Wno-unused-variable \
    -Wno-incompatible-pointer-types \
    -I"$SRC" -I"$ROOT" \
    -DUNIT_TEST_PARSE_EXPR \
    "$SRC/snobol4.tab.c" "$SRC/snobol4.lex.c" \
    /tmp/test_parse_expr_pat.c \
    -o /tmp/test_parse_expr_pat
echo "Build OK"
